Here's a simplified example of how to implement shared room state management for a karaoke system using TypeScript and WebSockets:

typescript
// shared-types/room.ts
export interface RoomState {
  id: string;
  users: Array<{ id: string; name: string; role: 'host' | 'guest' }>;
  queue: Array<{ id: string; title: string; artist: string; youtubeId: string; addedBy: string }>;
  currentSongId: string | null;
  isPlaying: boolean;
  playbackPosition: number;
}

export type RoomEvent = 
  | { type: 'USER_JOINED'; user: { id: string; name: string } }
  | { type: 'USER_LEFT'; userId: string }
  | { type: 'SONG_ADDED'; song: { id: string; title: string; artist: string; youtubeId: string; addedBy: string } }
  | { type: 'SONG_REMOVED'; songId: string }
  | { type: 'PLAYBACK_TOGGLED'; isPlaying: boolean }
  | { type: 'PLAYBACK_SEEKED'; position: number }
  | { type: 'NEXT_SONG' };

// backend/roomManager.ts
import { WebSocket } from 'ws';
import { RoomState, RoomEvent } from 'shared-types/room';

class RoomManager {
  private rooms = new Map<string, { state: RoomState; sockets: Set<WebSocket> }>();

  createRoom(roomId: string, hostId: string, hostName: string) {
    const roomState: RoomState = {
      id: roomId,
      users: [{ id: hostId, name: hostName, role: 'host' }],
      queue: [],
      currentSongId: null,
      isPlaying: false,
      playbackPosition: 0
    };
    this.rooms.set(roomId, { state: roomState, sockets: new Set() });
    return roomState;
  }

  broadcastEvent(roomId: string, event: RoomEvent) {
    const room = this.rooms.get(roomId);
    if (!room) return;

    // Update state based on event
    this.applyEvent(room.state, event);

    // Broadcast to all connected clients
    const message = JSON.stringify({ type: 'ROOM_UPDATE', event, state: room.state });
    room.sockets.forEach(socket => {
      if (socket.readyState === WebSocket.OPEN) {
        socket.send(message);
      }
    });
  }

  private applyEvent(state: RoomState, event: RoomEvent) {
    switch (event.type) {
      case 'USER_JOINED':
        state.users.push({ id: event.user.id, name: event.user.name, role: 'guest' });
        break;
      case 'SONG_ADDED':
        state.queue.push(event.song);
        if (!state.currentSongId && state.queue.length === 1) {
          state.currentSongId = event.song.id;
        }
        break;
      case 'PLAYBACK_TOGGLED':
        state.isPlaying = event.isPlaying;
        break;
      // ... other event handlers
    }
  }
}


Key components to implement:
1. Define shared types for room state and events
2. Create a central room manager that handles state and broadcasts changes
3. Use WebSocket connections for real-time updates
4. Implement client-side state management that synchronizes with the server state
